@@ -159,6 +163,8 @@ func Default() (*Config, error) {

 	cfg.UI.StatusTail = defaultStatusTail

+	cfg.Daemon.StopTimeoutSec = 5
+
 	cfg.Metrics.Enabled = false
 	cfg.Metrics.Addr = "127.0.0.1:9317"

@@ -24,7 +24,7 @@ func TestWaitForShutdownSucceedsWhenPidFileRemoved(t *testing.T) {
 		time.Sleep(100 * time.Millisecond)
 		_ = os.Remove(cfg.Paths.PidPath)
 	}()
-	if err := waitForShutdown(cfg.Paths.ConfigPath, 2*time.Second); err != nil {
+	if err := waitForShutdown(cfg.Paths.ConfigPath); err != nil {
 		t.Fatalf("expected success, got %v", err)
 	}
 }
@@ -41,7 +41,11 @@ func TestWaitForShutdownTimesOutOnAlivePid(t *testing.T) {
 	if err := os.WriteFile(cfg.Paths.PidPath, []byte(fmt.Sprintf("%d", selfPid)), 0o644); err != nil {
 		t.Fatalf("write pid: %v", err)
 	}
-	if err := waitForShutdown(cfg.Paths.ConfigPath, 300*time.Millisecond); err == nil {
+	cfg.Daemon.StopTimeoutSec = 0.3
+	if err := config.Save(cfg, cfg.Paths.ConfigPath); err != nil {
+		t.Fatalf("save cfg: %v", err)
+	}
+	if err := waitForShutdown(cfg.Paths.ConfigPath); err == nil {
 		t.Fatalf("expected timeout error")
 	}
 }
